-- Generated by render.py — load seed CSVs into DEMO_DYNAMICS_APP.PUBLIC
USE ROLE SYSADMIN;
USE SCHEMA DEMO_DYNAMICS_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

COPY INTO CUSTOMERS (CUSTOMER_ID,CUSTOMER_NUMBER,DISPLAY_NAME,ADDRESS_COUNTRY,CUSTOMER_TYPE,CREDIT_LIMIT,BALANCE_DUE) FROM @DEMO_SEED_STAGE/CUSTOMERS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO PRODUCTS (PRODUCT_ID,ITEM_NUMBER,DISPLAY_NAME,CATEGORY,UNIT_PRICE,UNIT_COST,INVENTORY) FROM @DEMO_SEED_STAGE/PRODUCTS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO VENDORS (VENDOR_ID,VENDOR_NUMBER,DISPLAY_NAME,COUNTRY,BALANCE) FROM @DEMO_SEED_STAGE/VENDORS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO SALES_ORDERS (ORDER_ID,ORDER_NUMBER,ORDER_DATE,CUSTOMER_ID,STATUS,CURRENCY_CODE,TOTAL_EXCL_TAX,TOTAL_INCL_TAX) FROM @DEMO_SEED_STAGE/SALES_ORDERS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO SALES_ORDER_LINES (LINE_ID,ORDER_ID,LINE_TYPE,PRODUCT_ID,QUANTITY,UNIT_PRICE,LINE_AMOUNT) FROM @DEMO_SEED_STAGE/SALES_ORDER_LINES.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
