COPY INTO GL_ENTRIES (ENTRY_ID,POSTING_DATE,ACCOUNT_NUMBER,ACCOUNT_NAME,DEBIT_AMOUNT,CREDIT_AMOUNT,DOCUMENT_TYPE) FROM @DEMO_SEED_STAGE/GL_ENTRIES.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO COMPANY_KNOWLEDGE_BASE (DOC_ID,TITLE,CATEGORY,AUDIENCE,CONTENT) FROM @DEMO_SEED_STAGE/COMPANY_KNOWLEDGE_BASE.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;

-- Post-load verification: every data table should be non-empty.
SELECT * FROM (
    SELECT 'CUSTOMERS' AS TBL, COUNT(*) AS N FROM CUSTOMERS
    UNION ALL SELECT 'PRODUCTS' AS TBL, COUNT(*) AS N FROM PRODUCTS
    UNION ALL SELECT 'VENDORS' AS TBL, COUNT(*) AS N FROM VENDORS
    UNION ALL SELECT 'SALES_ORDERS' AS TBL, COUNT(*) AS N FROM SALES_ORDERS
    UNION ALL SELECT 'SALES_ORDER_LINES' AS TBL, COUNT(*) AS N FROM SALES_ORDER_LINES
    UNION ALL SELECT 'INVOICES' AS TBL, COUNT(*) AS N FROM INVOICES
    UNION ALL SELECT 'GL_ENTRIES' AS TBL, COUNT(*) AS N FROM GL_ENTRIES
    UNION ALL SELECT 'COMPANY_KNOWLEDGE_BASE' AS TBL, COUNT(*) AS N FROM COMPANY_KNOWLEDGE_BASE
) ORDER BY N ASC, TBL;
